Method Name: isWriteable
Method Code:
/**
* Checks if the application is allowed to write to the file.
*
* @param file File to be checked.
*
* @return <code>true</code> if the file is writeable and <code>false</code> otherwise.
*/
    protected boolean isWriteable(File file) {
        if (file.exists()) {
            // Check the existing file.
            if (!file.canWrite()) {
                return false;
            }
        } else {
            // Check the file that doesn't exist yet.
            // Create a new file. The file is writeable if
            // the creation succeeds.
            try {
                file.createNewFile();
            } catch(IOException ioe) {
                return false;
            }
        }
        return true;
    }

